(async () => {
  try {
    const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));
    let passwordInput = document.querySelector('input[name="current_password"][type="password"]');
    if (!passwordInput) {
      let emailElement = null;
      emailElement = document.querySelector('a[href="/settings/email"]');
      if (!emailElement) {
        const tabs = Array.from(document.querySelectorAll('a[role="tab"][data-testid="pivot"]'));
        emailElement = tabs.find(tab => {
          const text = (tab.textContent || '').trim();
          return text.includes('Email') || text.includes('メール') || text.includes('@');
        });
      }
      if (!emailElement) {
        const links = Array.from(document.querySelectorAll('a[role="tab"]'));
        emailElement = links.find(link => {
          const text = (link.textContent || '').trim();
          const span = link.querySelector('span');
          const spanText = span ? (span.textContent || '').trim() : '';
          return text.includes('Email') || text.includes('メール') || spanText === 'Email' || spanText === 'メール';
        });
      }
      if (emailElement) {
        return { didAction: true, reason: 'パスワード入力画面が表示されていませんが、メールアドレス欄が表示されているためスキップしました' };
      }
      return { didAction: false, reason: 'パスワード入力フィールドが見つかりませんでした' };
    }
    const rawPassword = '{{db_x_password}}';
    const password = (rawPassword || '').trim();
    if (!password || !password.trim()) {
      return { didAction: false, reason: 'db_x_password が指定されていません' };
    }
    passwordInput.focus();
    passwordInput.scrollIntoView({ behavior: 'smooth', block: 'center' });
    await sleep(200);
    const setter = Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, 'value')?.set;
    if (setter) {
      setter.call(passwordInput, password);
    } else {
      passwordInput.value = password;
    }
    passwordInput.dispatchEvent(new Event('input', { bubbles: true }));
    passwordInput.dispatchEvent(new Event('change', { bubbles: true }));
    await sleep(300);
    let confirmButton = null;
    const container = passwordInput.closest('section,[role="dialog"],form') || document;
    const buttonsInContainer = Array.from(container.querySelectorAll('button, [role="button"]'));
    confirmButton = buttonsInContainer.find(btn => {
      const text = (btn.textContent || '').trim().toLowerCase();
      return text === 'confirm' || text.includes('confirm') || text.includes('確認');
    });
    if (!confirmButton) {
      const allButtons = Array.from(document.querySelectorAll('button, [role="button"]'));
      confirmButton = allButtons.find(btn => {
        const text = (btn.textContent || '').trim().toLowerCase();
        return text === 'confirm' || text.includes('confirm') || text.includes('確認');
      });
    }
    if (!confirmButton) {
      return { didAction: false, reason: 'Confirm ボタンが見つかりませんでした' };
    }
    confirmButton.scrollIntoView({ behavior: 'smooth', block: 'center' });
    await sleep(200);
    confirmButton.click();
    confirmButton.dispatchEvent(new MouseEvent('click', { bubbles: true, cancelable: true, view: window }));
    await sleep(1000);
    return { didAction: true, reason: 'パスワードを入力して Confirm ボタンをクリックしました' };
  } catch (e) {
    return { didAction: false, reason: 'エラー: ' + String(e) };
  }
})()

