(async () => {
  try {
    const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));
    let codeInput = null;
    const dialogs = Array.from(document.querySelectorAll('[role="dialog"][aria-modal="true"], [role="dialog"]'));
    const targetDialog = dialogs.find(el => {
      const text = (el.textContent || '').toLowerCase();
      return text.includes('we sent you a code') || text.includes('enter it below to verify your email');
    }) || dialogs[0] || null;
    if (targetDialog) {
      codeInput = targetDialog.querySelector('input[name="verfication_code"]') || targetDialog.querySelector('input[name="verification_code"]');
      if (!codeInput) {
        const labels = Array.from(targetDialog.querySelectorAll('label'));
        for (const label of labels) {
          const labelText = (label.textContent || '').toLowerCase();
          if (labelText.includes('verification code') || labelText.includes('verification') || labelText.includes('code') || labelText.includes('確認コード') || labelText.includes('確認')) {
            const directInput = label.querySelector('input');
            if (directInput) {
              codeInput = directInput;
              break;
            }
            const forAttr = label.getAttribute('for');
            if (forAttr) {
              const inputById = document.getElementById(forAttr);
              if (inputById && inputById.tagName === 'INPUT') {
                codeInput = inputById;
                break;
              }
            }
          }
        }
      }
    }
    if (!codeInput) {
      codeInput = document.querySelector('input[name="verfication_code"]') || document.querySelector('input[name="verification_code"]');
    }
    if (!codeInput) {
      return { didAction: false, reason: '確認コード入力フィールドが見つかりませんでした' };
    }
    const verificationCode = '{{pr_verification_code}}';
    const code = (verificationCode || '').trim();
    if (!code || code.length === 0) {
      return { didAction: false, reason: '確認コードが指定されていません' };
    }
    codeInput.focus();
    codeInput.scrollIntoView({ behavior: 'smooth', block: 'center' });
    await sleep(200);
    const setter = Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, 'value')?.set;
    if (setter) {
      setter.call(codeInput, code);
    } else {
      codeInput.value = code;
    }
    codeInput.dispatchEvent(new Event('input', { bubbles: true }));
    codeInput.dispatchEvent(new Event('change', { bubbles: true }));
    await sleep(300);
    return { didAction: true, reason: '確認コードを入力しました: ' + code };
  } catch (e) {
    return { didAction: false, reason: 'エラー: ' + String(e) };
  }
})()

